package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonArrayTest {

  private JsonArray jsonArray;
  private JsonElement singleElementMock;

  @BeforeEach
  public void setUp() {
    jsonArray = new JsonArray();
    singleElementMock = mock(JsonElement.class);
  }

  @Test
  public void testGetAsCharacter_delegatesToSingleElement() {
    // Add mock element to jsonArray
    jsonArray.add(singleElementMock);

    // Define behavior of singleElementMock.getAsCharacter()
    when(singleElementMock.getAsCharacter()).thenReturn('x');

    // Call the focal method
    char result = jsonArray.getAsCharacter();

    // Verify delegation and result
    verify(singleElementMock).getAsCharacter();
    assertEquals('x', result);
  }

  @Test
  public void testGetAsCharacter_whenEmpty_throwsIndexOutOfBoundsException() throws Exception {
    // jsonArray is empty, so getAsSingleElement() should throw IndexOutOfBoundsException

    // Use reflection to invoke private method getAsSingleElement which throws if empty
    var getAsSingleElementMethod = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElementMethod.setAccessible(true);

    assertThrows(IndexOutOfBoundsException.class, () -> {
      getAsSingleElementMethod.invoke(jsonArray);
    });

    // Because getAsCharacter calls getAsSingleElement, it should also throw IndexOutOfBoundsException
    assertThrows(IndexOutOfBoundsException.class, () -> {
      jsonArray.getAsCharacter();
    });
